import { useControl } from '@ui/components/formControls/hooks';
import { InputControl, InputControlProps } from '../InputControl';

export const FormPostalCodeControl = ({
  label,
  placeholder,
  ...props
}: Omit<InputControlProps, 'onChange' | 'value'>) => {
  const { field } = useControl(props);

  return (
    <InputControl
      autoComplete="postal-code"
      label={label ?? 'Zip'}
      placeholder={placeholder ?? '70112'}
      type="number"
      {...props}
      {...field}
    />
  );
};
